unsafe_example:
// UNSAFE: user input used directly as file path
String filename = request.getParameter("file");
FileInputStream fis = new FileInputStream("/opt/uploads/" + filename);
// Attacker sends: file=../../etc/passwd

safe_example:
// SAFE: normalize + containment check
String filename = request.getParameter("file");
Path baseDir = Paths.get("/opt/uploads").toAbsolutePath();
Path resolved = baseDir.resolve(filename).normalize();
if (!resolved.startsWith(baseDir)) {
    throw new SecurityException("path traversal attempt");
}
FileInputStream fis = new FileInputStream(resolved.toFile());
